```class Solution {
public:
    long long smallestNumber(long long num) {
        int len = (int)log10(num);
        long long result = num;
        for (int i = len - 1; i >= 0; i--) {
            result /= 10;
            result *= 10;
            result += num % 10;
            num = result;
        }
        return num;
    }
};
